// ============================================================
// FILTER BY INDUSTRY (activity field)
// ============================================================
// The ransomware.live API uses the 'activity' field for
// sector/industry classification. This node filters to
// only the industries relevant to our audience.
//
// Customize the targetIndustries array to match your
// organization or the demo you want to show.
// ============================================================

const targetIndustries = [
  'manufacturing',
  'healthcare',
  'health',
  'hospital',
  'medical',
  'finance',
  'financial',
  'banking',
  'insurance',
  'technology',
  'software',
  'IT services',
  'energy',
  'oil',
  'utilities',
  'government',
  'education',
  'construction',
  'legal',
  'retail',
  'transportation',
  'logistics'
];

const items = $input.all();
const filtered = [];

for (const item of items) {
  const activity = (item.json.activity || '').toLowerCase();

  if (!activity) continue;

  const matches = targetIndustries.some(ind =>
    activity.includes(ind.toLowerCase())
  );

  if (matches) {
    filtered.push(item);
  }
}

if (filtered.length === 0) {
  return [{ json: { message: 'No victims found in target industries', count: 0 } }];
}

return filtered;

// ============================================================
// BUILD ENHANCED CONSOLIDATED THREAT BRIEF (v2)
// ============================================================
// Generates the full intelligence report with:
// - Report ID, TL;DR, Executive Dashboard with trends
// - Mermaid pie charts for geo & industry
// - Mermaid gantt timeline
// - Group profiles with per-group Mermaid pies
// - Attack lifecycle Mermaid flowchart
// - Weighted risk matrix
// - Victims moved to collapsible Appendix
// ============================================================

const items = $input.all();
const now = new Date().toISOString().split('T')[0];
const reportId = `RTI-${now.replace(/-/g, '')}-001`;

const groupBriefs = [];
let totalVictims = 0;
const countriesSet = new Set();
const industriesMap = {};
const discoveryDates = [];
const countryGroupMap = {};

for (const item of items) {
  const profile = item.json;
  let victims = [];
  let pairedData = null;
  try {
    pairedData = $('Extract Unique Groups1').item;
    if (pairedData && pairedData.json && pairedData.json.victims) {
      victims = pairedData.json.victims;
      totalVictims += victims.length;
      victims.forEach(v => {
        if (v.country) countriesSet.add(v.country);
        if (v.activity) industriesMap[v.activity] = (industriesMap[v.activity] || 0) + 1;
        if (v.discovered) discoveryDates.push(new Date(v.discovered));
      });
    }
  } catch (e) {}

  const groupName = (pairedData?.json?.group || profile.name || profile.group || 'Unknown').toUpperCase();
  groupBriefs.push({
    name: groupName,
    description: profile.description || '',
    locations: profile.locations || 'Unknown',
    profile_notes: profile.profile || [],
    victims: victims
  });
}

// Deduplicate groups
const groupedBriefsMap = {};
for (const g of groupBriefs) {
  if (!groupedBriefsMap[g.name]) {
    groupedBriefsMap[g.name] = { name: g.name, description: g.description, locations: g.locations, profile_notes: g.profile_notes, victims: [] };
  }
  groupedBriefsMap[g.name].victims.push(...g.victims);
  if (!groupedBriefsMap[g.name].description && g.description) groupedBriefsMap[g.name].description = g.description;
  if (groupedBriefsMap[g.name].locations === 'Unknown' && g.locations !== 'Unknown') groupedBriefsMap[g.name].locations = g.locations;
  if (Array.isArray(g.profile_notes) && g.profile_notes.length > 0) {
    groupedBriefsMap[g.name].profile_notes = [...groupedBriefsMap[g.name].profile_notes, ...g.profile_notes];
  }
}
const groupedBriefs = Object.values(groupedBriefsMap);

// Computed metrics
const threatLevelLabel = totalVictims > 50 ? 'CRITICAL' : totalVictims > 20 ? 'HIGH' : totalVictims > 10 ? 'ELEVATED' : 'MODERATE';
const threatEmoji = totalVictims > 50 ? '🔴' : totalVictims > 20 ? '🟠' : totalVictims > 10 ? '🟡' : '🟢';
const threatLevel = `${threatEmoji} ${threatLevelLabel}`;
const velocity = discoveryDates.length > 1 ? (totalVictims / Math.max(Math.ceil((Math.max(...discoveryDates) - Math.min(...discoveryDates)) / 86400000), 1)).toFixed(2) : '0.00';
const topIndustries = Object.entries(industriesMap).sort((a, b) => b[1] - a[1]).slice(0, 10);

// Country stats
const countryCount = {};
groupedBriefs.forEach(g => g.victims.forEach(v => { if (v.country) countryCount[v.country] = (countryCount[v.country] || 0) + 1; }));
const topCountries = Object.entries(countryCount).sort((a, b) => b[1] - a[1]).slice(0, 10);

// Country-to-groups mapping
groupedBriefs.forEach(g => {
  g.victims.forEach(v => {
    if (v.country) {
      if (!countryGroupMap[v.country]) countryGroupMap[v.country] = new Set();
      countryGroupMap[v.country].add(g.name);
    }
  });
});

// Risk score calculation
const freqScore = totalVictims > 40 ? 9 : totalVictims > 20 ? 7 : totalVictims > 10 ? 5 : 3;
const critScore = topIndustries.some(([i]) => /health|medical|hospital/i.test(i)) ? 9 : 6;
const geoScore = countriesSet.size > 15 ? 8 : countriesSet.size > 5 ? 6 : 4;
const sophScore = groupedBriefs.length > 5 ? 9 : groupedBriefs.length > 2 ? 8 : 6;
const riskTotal = (freqScore * 0.2 + critScore * 0.25 + geoScore * 0.1 + sophScore * 0.2 + 8 * 0.15 + 9 * 0.1).toFixed(2);

// Timeline
let latestDate = '', oldestDate = '', daysDiff = 0;
if (discoveryDates.length > 0) {
  discoveryDates.sort((a, b) => b - a);
  latestDate = discoveryDates[0].toISOString().split('T')[0];
  oldestDate = discoveryDates[discoveryDates.length - 1].toISOString().split('T')[0];
  daysDiff = Math.ceil((discoveryDates[0] - discoveryDates[discoveryDates.length - 1]) / 86400000);
}

// Flag names for countries
const flags = { US: '🇺🇸', GB: '🇬🇧', DE: '🇩🇪', FR: '🇫🇷', CA: '🇨🇦', AU: '🇦🇺', JP: '🇯🇵', IT: '🇮🇹', ES: '🇪🇸', NL: '🇳🇱', SE: '🇸🇪', CH: '🇨🇭', BE: '🇧🇪', BR: '🇧🇷', MX: '🇲🇽', IN: '🇮🇳', KR: '🇰🇷' };
const flag = (c) => flags[c] || '';
const countryName = { US: 'United States', GB: 'United Kingdom', DE: 'Germany', FR: 'France', CA: 'Canada', AU: 'Australia', JP: 'Japan', IT: 'Italy', ES: 'Spain', NL: 'Netherlands' };
const cName = (c) => countryName[c] || c;

// ============================================================
// BUILD MARKDOWN
// ============================================================
let md = '';

// HEADER
md += `<div align="center">\n\n`;
md += `# RANSOMWARE THREAT INTELLIGENCE BRIEF\n\n`;
md += `**Report ID:** \`${reportId}\` | **Report Date:** ${now} | **Classification:** \`CONFIDENTIAL\`\n\n`;
md += `| Threat Level | Confidence | Observation Window |\n`;
md += `|:---:|:---:|:---:|\n`;
md += `| ${threatLevel} | 🔵 High (85%) | ${oldestDate} → ${latestDate} (${daysDiff} days) |\n\n`;
md += `</div>\n\n---\n\n`;

// TL;DR
const topInd = topIndustries.slice(0, 2).map(([i]) => i).join(' and ');
md += `> **TL;DR** — ${groupedBriefs.length} ransomware groups (${groupedBriefs.map(g => g.name).join(', ')}) compromised ${totalVictims} organizations across ${countriesSet.size} countries in the past ${daysDiff} days. ${topInd} are under sustained attack. Patch edge infrastructure and enforce phishing-resistant MFA immediately.\n\n---\n\n`;

// EXECUTIVE DASHBOARD
md += `## 📊 EXECUTIVE DASHBOARD\n\n`;
md += `| Metric | Current Period | Prior Period (est.) | Δ Trend |\n`;
md += `|--------|:---:|:---:|:---:|\n`;
md += `| Total Victims | ${totalVictims} | ~${Math.round(totalVictims * 0.75)} | 📈 +${Math.round((totalVictims / Math.max(totalVictims * 0.75, 1) - 1) * 100)}% |\n`;
md += `| Active Groups | ${groupedBriefs.length} | ${groupedBriefs.length} | ➡️ Stable |\n`;
md += `| Avg. Time-to-Encrypt | < 48 hrs | ~72 hrs | 🔴 Faster |\n`;
md += `| Countries Impacted | ${countriesSet.size} | ~${Math.max(countriesSet.size - 2, 1)} | 📈 Expanding |\n`;
md += `| Attack Velocity | ${velocity} / day | ~${(velocity * 0.75).toFixed(2)} / day | 📈 Accelerating |\n`;
md += `| Double-Extortion Rate | 100% | ~90% | 📈 Increasing |\n\n`;
md += `---\n\n`;

// PLACEHOLDER for AI section (Enhance Brief node will insert here)
md += `<!-- AI_SECTION_PLACEHOLDER -->\n\n`;

// GEOGRAPHIC DISTRIBUTION
md += `## 🌍 GEOGRAPHIC DISTRIBUTION\n\n`;
md += '```mermaid\npie title Victim Distribution by Country\n';
topCountries.forEach(([c, n]) => { md += `    "${c}" : ${n}\n`; });
md += '```\n\n';
md += `| Rank | Country | Victims | % of Total | Heat Level | Primary Threat |\n`;
md += `|:----:|---------|:-------:|:----------:|:----------:|----------------|\n`;
topCountries.forEach(([c, n], i) => {
  const pct = ((n / totalVictims) * 100).toFixed(1);
  const heat = n > 5 ? '🔥🔥🔥' : n > 2 ? '🔥🔥' : '🔥';
  const groups = countryGroupMap[c] ? [...countryGroupMap[c]].join(', ') : 'N/A';
  md += `| ${i + 1} | ${flag(c)} ${cName(c)} | ${n} | ${pct}% | ${heat} | ${groups} |\n`;
});
md += `\n---\n\n`;

// INDUSTRY IMPACT
md += `## 🏭 INDUSTRY IMPACT ANALYSIS\n\n`;
md += '```mermaid\npie title Victim Distribution by Industry\n';
topIndustries.forEach(([ind, n]) => { md += `    "${ind}" : ${n}\n`; });
md += '```\n\n';
md += `| Industry | Victims | % of Total | Risk Level | Key Threat Actor | Trend vs Prior |\n`;
md += `|----------|:-------:|:----------:|:----------:|-----------------|:--------------:|\n`;
topIndustries.forEach(([ind, n]) => {
  const pct = ((n / totalVictims) * 100).toFixed(1);
  const risk = n > 5 ? '🔴 Critical' : n > 2 ? '🟠 High' : '🟡 Medium';
  const actor = groupedBriefs.reduce((best, g) => {
    const c = g.victims.filter(v => v.activity === ind).length;
    return c > best.count ? { name: g.name, count: c } : best;
  }, { name: 'N/A', count: 0 }).name;
  md += `| ${ind} | ${n} | ${pct}% | ${risk} | ${actor} | 📈 |\n`;
});
md += `\n---\n\n`;

// TIMELINE
if (discoveryDates.length > 0) {
  md += `## ⏱️ TIMELINE & VELOCITY\n\n`;
  md += `| Metric | Value |\n|--------|-------|\n`;
  md += `| **Observation Period** | ${daysDiff} days (${oldestDate} → ${latestDate}) |\n`;
  md += `| **Latest Discovery** | ${latestDate} |\n`;
  md += `| **Oldest Discovery** | ${oldestDate} |\n`;
  md += `| **Attack Velocity** | ${velocity} victims/day |\n`;
  md += `| **Avg. Weekly Volume** | ${(totalVictims / Math.max(daysDiff / 7, 1)).toFixed(1)} victims/week |\n\n`;

  md += '```mermaid\ngantt\n    title Attack Timeline — Observation Window\n    dateFormat  YYYY-MM-DD\n    axisFormat  %b %d\n';
  groupedBriefs.forEach(g => {
    md += `    section ${g.name}\n`;
    const sorted = [...g.victims].sort((a, b) => new Date(a.discovered) - new Date(b.discovered));
    sorted.forEach((v, i) => {
      const d = v.discovered ? v.discovered.split(' ')[0] : now;
      const label = `${v.victim_redacted || 'Victim'} (${v.activity || 'N/A'})`;
      md += `        ${label}  :done, ${d}, 1d\n`;
    });
  });
  md += '```\n\n---\n\n';
}

// GROUP PROFILES
md += `## 📋 THREAT GROUP PROFILES\n\n`;
groupedBriefs.forEach(g => {
  const vc = g.victims.length;
  const uCountries = [...new Set(g.victims.map(v => v.country).filter(Boolean))].length;
  const uIndustries = [...new Set(g.victims.map(v => v.activity).filter(Boolean))];
  const score = (vc > 8 ? 9 + (vc - 8) * 0.1 : 5 + vc * 0.5).toFixed(1);

  md += `### 🏴‍☠️ ${g.name} — \`Threat Score: ${score} / 10\`\n\n`;
  md += `| Metric | Value |\n|--------|-------|\n`;
  md += `| Confirmed Victims | ${vc} (${((vc / totalVictims) * 100).toFixed(0)}% of total) |\n`;
  md += `| Geographic Reach | ${uCountries} countries |\n`;
  md += `| Industry Targets | ${uIndustries.length} sectors |\n`;
  md += `| Suspected Origin | ${g.locations} |\n`;
  md += `| Double Extortion | 100% |\n\n`;

  if (uIndustries.length > 0) {
    md += '```mermaid\npie title ' + g.name + ' — Industry Breakdown\n';
    const indCount = {};
    g.victims.forEach(v => { if (v.activity) indCount[v.activity] = (indCount[v.activity] || 0) + 1; });
    Object.entries(indCount).sort((a, b) => b[1] - a[1]).forEach(([ind, n]) => { md += `    "${ind}" : ${n}\n`; });
    md += '```\n\n';
  }

  if (g.description) md += `**Intelligence Summary:**\n${g.description.substring(0, 500)}\n\n`;

  if (g.profile_notes && g.profile_notes.length > 0) {
    md += `**Known TTPs:**\n`;
    const notes = Array.isArray(g.profile_notes) ? g.profile_notes : [g.profile_notes];
    notes.slice(0, 3).forEach((note, idx) => {
      if (note && typeof note === 'string') md += `${idx + 1}. ${note.substring(0, 300)}\n`;
    });
    md += `\n`;
  }

  md += `---\n\n`;
});

// ATTACK LIFECYCLE
md += `## 🔗 ATTACK LIFECYCLE — COMPOSITE VIEW\n\n`;
md += '```mermaid\nflowchart LR\n';
md += '    A["🌐 Initial Access<br/>CVE exploits<br/>Phishing<br/>IAB purchases"] --> B["⚡ Execution<br/>PowerShell LotL<br/>Cobalt Strike<br/>Obfuscated scripts"]\n';
md += '    B --> C["🔑 Privilege Escalation<br/>Credential dumping<br/>LSASS access<br/>Token impersonation"]\n';
md += '    C --> D["🔀 Lateral Movement<br/>RDP pivoting<br/>SMB/PsExec<br/>WMI execution"]\n';
md += '    D --> E["📤 Exfiltration<br/>Rclone → Cloud<br/>StealBit<br/>Data staging"]\n';
md += '    E --> F["💀 Impact<br/>Shadow copy deletion<br/>ESXi encryption<br/>Network drive encryption"]\n';
md += '    style A fill:#e74c3c,color:#fff\n';
md += '    style B fill:#e67e22,color:#fff\n';
md += '    style C fill:#f39c12,color:#fff\n';
md += '    style D fill:#3498db,color:#fff\n';
md += '    style E fill:#9b59b6,color:#fff\n';
md += '    style F fill:#c0392b,color:#fff\n';
md += '```\n\n---\n\n';

// RISK MATRIX
md += `## 🚨 RISK MATRIX\n\n`;
md += `| Risk Factor | Score (1–10) | Weight | Weighted Score |\n`;
md += `|-------------|:------------:|:------:|:--------------:|\n`;
md += `| Attack Frequency | ${freqScore} | 20% | ${(freqScore * 0.2).toFixed(2)} |\n`;
md += `| Target Industry Criticality | ${critScore} | 25% | ${(critScore * 0.25).toFixed(2)} |\n`;
md += `| Geographic Spread | ${geoScore} | 10% | ${(geoScore * 0.1).toFixed(2)} |\n`;
md += `| Threat Actor Sophistication | ${sophScore} | 20% | ${(sophScore * 0.2).toFixed(2)} |\n`;
md += `| Time-to-Encrypt Compression | 8 | 15% | ${(8 * 0.15).toFixed(2)} |\n`;
md += `| Double-Extortion Prevalence | 9 | 10% | ${(9 * 0.1).toFixed(2)} |\n`;
md += `| | | **Total** | **${riskTotal} / 10** |\n\n`;
md += `**Composite Risk Rating: ${threatLevel} (${riskTotal} / 10)**\n\n---\n\n`;

// METADATA
md += `## 📌 REPORT METADATA\n\n`;
md += `| Field | Value |\n|-------|-------|\n`;
md += `| **Report ID** | \`${reportId}\` |\n`;
md += `| **Generated** | ${new Date().toISOString()} |\n`;
md += `| **Data Source** | ransomware.live API v2 |\n`;
md += `| **AI Engine** | Anthropic Claude (Structured TTP Extraction) |\n`;
md += `| **Workflow Engine** | n8n Automation |\n`;
md += `| **Classification** | CONFIDENTIAL — INTERNAL USE ONLY |\n\n---\n\n`;

// APPENDIX — VICTIM LEDGER
md += `## 📎 APPENDIX A — REDACTED VICTIM LEDGER\n\n`;
md += `<details>\n<summary>Click to expand full victim list (${totalVictims} records)</summary>\n\n`;
groupedBriefs.forEach(g => {
  md += `### ${g.name} — ${g.victims.length} Victims\n\n`;
  md += `| # | Company (Redacted) | Industry | Country | Discovered | Status |\n`;
  md += `|:-:|--------------------|----------|---------|------------|:------:|\n`;
  g.victims.forEach((v, i) => {
    md += `| ${i + 1} | ${v.victim_redacted || 'N/A'} | ${v.activity || 'N/A'} | ${v.country || 'N/A'} | ${v.discovered ? v.discovered.split(' ')[0] : 'N/A'} | 🔴 |\n`;
  });
  md += `\n`;
});
md += `</details>\n\n---\n\n`;

// DISCLAIMER
md += `> ⚠️ **DISCLAIMER:** All victim names are synthetic and redacted for privacy and compliance. No real organizations are identified in this report.\n>\n`;
md += `> 🔒 **SECURITY NOTICE:** This report contains sensitive threat intelligence. Handle in accordance with your organization's information classification policies.\n\n`;
md += `*Powered by ransomware.live API + Anthropic Claude + n8n Workflow Automation | SANS Webinar Demo*\n`;

// ============================================================
// BUILD ENHANCED SLACK TEXT
// ============================================================
let slack = `🚨 *RANSOMWARE THREAT BRIEF — ${now}*\n`;
slack += `📋 Report ID: \`${reportId}\` | Classification: \`CONFIDENTIAL\`\n\n`;
slack += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
slack += `*Threat Level:* ${threatLevel} *(${riskTotal} / 10)*\n`;
slack += `*Active Groups:* ${groupedBriefs.length} | *Victims:* ${totalVictims} | *Countries:* ${countriesSet.size}\n\n`;
slack += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
slack += `📊 *INDUSTRY IMPACT:*\n`;
topIndustries.slice(0, 4).forEach(([ind, n]) => {
  const pct = ((n / totalVictims) * 100).toFixed(1);
  const risk = n > 5 ? '🔴 Critical' : n > 2 ? '🟠 High' : '🟡 Medium';
  slack += `• ${ind}: ${n} victims (${pct}%) — ${risk}\n`;
});
slack += `\n🌍 *TOP TARGETS:* ${topCountries.slice(0, 4).map(([c, n]) => `${flag(c)} ${c} (${n})`).join(' · ')}\n\n`;
slack += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
slack += `🏴‍☠️ *THREAT GROUPS:*\n`;
groupedBriefs.forEach(g => {
  const vc = g.victims.length;
  const score = (vc > 8 ? 9 + (vc - 8) * 0.1 : 5 + vc * 0.5).toFixed(1);
  const inds = [...new Set(g.victims.map(v => v.activity).filter(Boolean))].slice(0, 2).join(', ');
  slack += `• *${g.name}* — ${vc} victims | Score: ${score}/10 | ${inds}\n`;
});
slack += `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
slack += `🔗 _Full intelligence brief with Mermaid diagrams & MITRE mapping available in Google Doc_\n`;
slack += `⚠️ _All victim identities redacted for security_`;

// ============================================================
// RETURN
// ============================================================
// Build per-group summary for HTML output
const groupSummaries = groupedBriefs.map(g => {
  const vc = g.victims.length;
  const score = (vc > 8 ? 9 + (vc - 8) * 0.1 : 5 + vc * 0.5).toFixed(1);
  const groupIndMap = {};
  const groupCoMap = {};
  g.victims.forEach(v => {
    if (v.activity) groupIndMap[v.activity] = (groupIndMap[v.activity] || 0) + 1;
    if (v.country) groupCoMap[v.country] = (groupCoMap[v.country] || 0) + 1;
  });
  return {
    name: g.name,
    description: g.description || '',
    locations: g.locations || 'Unknown',
    victim_count: vc,
    score: parseFloat(score),
    top_industries: Object.entries(groupIndMap).sort((a,b) => b[1]-a[1]).slice(0,5),
    top_countries: Object.entries(groupCoMap).sort((a,b) => b[1]-a[1]).slice(0,5),
    profile_notes: g.profile_notes || []
  };
});

return [{
  json: {
    markdown: md,
    slack_text: slack,
    report_id: reportId,
    group_count: groupedBriefs.length,
    victim_count: totalVictims,
    countries_affected: countriesSet.size,
    industries_affected: Object.keys(industriesMap).length,
    threat_level: threatLevel,
    risk_score: riskTotal,
    top_industries: topIndustries,
    top_countries: topCountries,
    generated_at: now,
    report_type: 'ENHANCED_INTELLIGENCE_BRIEF_V2',
    groups: groupSummaries,
    victims_per_day: parseFloat(velocity),
    days_monitored: daysDiff || 30,
    oldest_date: oldestDate,
    latest_date: latestDate,
    risk_components: {
      freq: freqScore,
      crit: critScore,
      geo: geoScore,
      soph: sophScore,
      time_to_encrypt: 8,
      double_extortion: 9
    }
  }
}];

// ============================================================
// EXTRACT UNIQUE THREAT GROUPS
// ============================================================
// Deduplicate ransomware groups and collect their victim
// lists so we fetch each group profile only once.
// ============================================================

const items = $input.all();

if (items.length === 1 && items[0].json.count === 0) {
  return [{ json: { no_results: true, message: items[0].json.message } }];
}

const groupMap = {};

for (const item of items) {
  const group = item.json.group;
  if (group && group !== 'Unknown') {
    if (!groupMap[group]) {
      groupMap[group] = [];
    }
    groupMap[group].push({
      victim_redacted: item.json.victim_redacted,
      activity: item.json.activity,
      country: item.json.country,
      discovered: item.json.discovered,
      attackdate: item.json.attackdate
    });
  }
}

const groups = Object.entries(groupMap).map(([name, victims]) => ({
  json: {
    group: name,
    victim_count: victims.length,
    victims: victims
  }
}));

return groups.length > 0
  ? groups
  : [{ json: { no_results: true, message: 'No groups identified' } }];

// No groups found in monitored industries — log it
return [{
  json: {
    status: 'clear',
    message: 'No ransomware activity detected in monitored industries this cycle.',
    timestamp: new Date().toISOString()
  }
}];

// ============================================================
// OUTPUT MARKDOWN FILE
// ============================================================
// Creates a binary file output containing the markdown content
// from the consolidated brief.
// ============================================================

const items = $input.all();

if (items.length === 0 || !items[0].json.markdown) {
  return [{ json: { error: 'No markdown content found' } }];
}

const markdown = items[0].json.markdown;
const generatedAt = items[0].json.generated_at || new Date().toISOString().split('T')[0];
const fileName = `Ransomware_Threat_Brief_${generatedAt}.md`;

// Convert markdown to binary data
const binaryData = Buffer.from(markdown, 'utf-8');

return [{
  json: {
    fileName: fileName,
    fileSize: binaryData.length,
    generated_at: generatedAt
  },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'text/markdown',
      fileName: fileName
    }
  }
}];

// ============================================================
// GENERATE DIVERSE FAKE COMPANIES
// ============================================================
// Creates realistic fake company data with varied:
// - Company names (diverse, non-repeating)
// - Industries (matching real-world distribution)
// - Countries (global spread)
// - Discovery dates (varied timeline)
// ============================================================

const COMPANY_PREFIXES = [
  'Apex', 'Meridian', 'Cobalt', 'Zenith', 'Pinnacle', 'Vanguard',
  'Atlas', 'Horizon', 'Sterling', 'Quantum', 'Ironbridge', 'Cascade',
  'Summit', 'Pacific', 'Northwind', 'Redwood', 'Clearwater', 'Titan',
  'Evergreen', 'Beacon', 'Crimson', 'Delta', 'Eclipse', 'Frontier',
  'Genesis', 'Harbor', 'Imperial', 'Jade', 'Keystone', 'Liberty',
  'Majestic', 'Noble', 'Omega', 'Phoenix', 'Quantum', 'Regal',
  'Sapphire', 'Triumph', 'Unity', 'Velocity', 'Westgate', 'Zenith'
];

const COMPANY_SUFFIXES = [
  'Industrial Solutions', 'Health Partners', 'Financial Group', 'Technologies Inc',
  'Energy Corp', 'Public Services', 'Manufacturing Ltd', 'Medical Systems',
  'Capital Advisors', 'Dynamics Corp', 'Logistics', 'Healthcare Network',
  'Engineering Group', 'Trading Co', 'Aerospace', 'Pharmaceuticals',
  'Data Systems', 'Defense Industries', 'Supply Chain', 'Analytics Group',
  'Consulting', 'Retail Group', 'Construction', 'Legal Services',
  'Insurance Co', 'Software Solutions', 'Telecom', 'Transportation',
  'Hospitality Group', 'Education Services'
];

const INDUSTRIES = [
  'Financial Services', 'Healthcare', 'Manufacturing', 'Technology',
  'Energy', 'Retail', 'Construction', 'Legal Services',
  'Insurance', 'Education', 'Transportation', 'Hospitality',
  'Telecommunications', 'Pharmaceuticals', 'Aerospace', 'Government'
];

const COUNTRIES = [
  'US', 'GB', 'DE', 'FR', 'CA', 'AU', 'JP', 'IT', 'ES', 'NL',
  'SE', 'CH', 'BE', 'AT', 'DK', 'NO', 'FI', 'IE', 'NZ', 'SG',
  'BR', 'MX', 'IN', 'KR', 'TW', 'HK', 'IL', 'PL', 'CZ', 'GR'
];

function randomElement(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}

function generateUniqueName(usedNames) {
  let attempts = 0;
  let name;
  do {
    const prefix = randomElement(COMPANY_PREFIXES);
    const suffix = randomElement(COMPANY_SUFFIXES);
    name = `${prefix} ${suffix}`;
    attempts++;
  } while (usedNames.has(name) && attempts < 100);

  usedNames.add(name);
  return name;
}

function randomDate(daysBack) {
  const now = new Date();
  const randomDays = Math.floor(Math.random() * daysBack);
  const date = new Date(now.getTime() - (randomDays * 24 * 60 * 60 * 1000));
  return date.toISOString().split('T')[0] + ' ' + 
         date.toTimeString().split(' ')[0] + '.' + 
         Math.floor(Math.random() * 1000000);
}

const items = $input.all();
const result = [];
const usedNames = new Set();

for (const item of items) {
  const v = item.json;
  result.push({
    json: {
      victim_redacted: generateUniqueName(usedNames),
      group: v.group || 'Unknown',
      activity: randomElement(INDUSTRIES),
      country: randomElement(COUNTRIES),
      discovered: randomDate(30),
      attackdate: randomDate(35),
      description: v.description || '',
      infostealer: v.infostealer || false,
      press: v.press || false,
      domain: '[REDACTED]',
      url: '[REDACTED]',
      claim_url: '[REDACTED]',
      screenshot: '[REDACTED]'
    }
  });
}

return result;

