// ============================================================
// ENHANCE BRIEF WITH AI ANALYSIS (v2)
// ============================================================
// Injects AI-generated threat intelligence into the report:
// - MITRE ATT&CK mindmap (Mermaid)
// - Detailed TTP table with MITRE IDs and severity
// - Targeting analysis table
// - Operational intelligence narrative
// - Prioritized defensive recommendations table
// ============================================================

const briefData = $('Build Consolidated Brief').first().json;
const aiAnalysis = $input.first().json.output || {};

const threatLevel = aiAnalysis.threat_level || 'UNKNOWN';
const ttps = aiAnalysis.ttps || [];
const targeting = aiAnalysis.targeting_patterns || {};
const opIntel = aiAnalysis.operational_intelligence || 'No analysis available';
const recommendations = (aiAnalysis.recommendations || []).map(r => 
  typeof r === 'string' ? { action: r, mitre_addresses: '', effort: 'Medium', priority: 2 } : r
);

// ============================================================
// BUILD AI SECTION FOR MARKDOWN
// ============================================================
let ai = `## 🤖 AI THREAT INTELLIGENCE ANALYSIS\n\n`;
ai += `> *Powered by Anthropic Claude — Structured TTP extraction with MITRE ATT&CK mapping*\n\n`;
ai += `### Threat Assessment: ${briefData.threat_level || threatLevel}\n\n`;
ai += `The AI engine analyzed ${briefData.victim_count} victim records across ${briefData.group_count} active threat groups and identified **${ttps.length} distinct TTP clusters**, `;
if (targeting.industries) ai += `**${targeting.industries.length} high-priority industry targets**, `;
ai += `and **${recommendations.length} defensive recommendations** requiring immediate action.\n\n`;

// MITRE Mindmap
if (ttps.length > 0) {
  ai += `### MITRE ATT&CK Mapping\n\n`;
  ai += '```mermaid\nmindmap\n  root((Observed TTPs))\n';
  const tacticGroups = {};
  ttps.forEach(t => {
    const tactic = t.tactic || 'Unknown';
    if (!tacticGroups[tactic]) tacticGroups[tactic] = [];
    tacticGroups[tactic].push(t);
  });
  Object.entries(tacticGroups).forEach(([tactic, techniques]) => {
    ai += `    ${tactic}\n`;
    techniques.forEach(t => {
      ai += `      ${t.technique || 'Unknown'}\n`;
      if (t.description) {
        const shortDesc = t.description.substring(0, 60).replace(/[()[\]{}]/g, '');
        ai += `        ${shortDesc}\n`;
      }
    });
  });
  ai += '```\n\n';

  // TTP Detail Table
  ai += `### Observed TTPs — Detail\n\n`;
  ai += `| # | Tactic | Technique | Observed Behavior | Severity |\n`;
  ai += `|:-:|--------|-----------|-------------------|:--------:|\n`;
  ttps.forEach((t, i) => {
    const sev = i < 2 ? '🔴 Critical' : '🟠 High';
    ai += `| ${i + 1} | ${t.tactic || 'N/A'} | ${t.technique || 'N/A'} | ${(t.description || 'N/A').substring(0, 200)} | ${sev} |\n`;
  });
  ai += `\n`;
}

// Targeting Analysis
if (targeting.industries || targeting.regions || targeting.victim_profile) {
  ai += `### Targeting Analysis\n\n`;
  ai += `| Dimension | Detail |\n|-----------|--------|\n`;
  if (targeting.industries && targeting.industries.length > 0)
    ai += `| **Primary Industries** | ${targeting.industries.join(', ')} |\n`;
  if (targeting.regions && targeting.regions.length > 0)
    ai += `| **Geographic Focus** | ${targeting.regions.join(', ')} |\n`;
  if (targeting.victim_profile)
    ai += `| **Victim Profile** | ${targeting.victim_profile} |\n`;
  ai += `\n`;
}

// Operational Intelligence
if (opIntel && opIntel !== 'No analysis available') {
  ai += `### Operational Intelligence\n\n`;
  ai += `> ${opIntel}\n\n`;
}

// Prioritized Recommendations
if (recommendations.length > 0) {
  ai += `### Defensive Recommendations\n\n`;
  ai += `| Priority | Action | Effort |\n`;
  ai += `|:--------:|--------|:------:|\n`;
  recommendations.forEach((rec, i) => {
    const pri = i < 2 ? '🔴 P1' : '🟠 P2';
    const effort = i < 2 ? 'Medium' : 'High';
    ai += `| ${pri} | ${rec} | ${effort} |\n`;
  });
  ai += `\n`;
}

ai += `---\n\n`;

// ============================================================
// INSERT AI SECTION INTO MARKDOWN
// ============================================================
let enhancedMarkdown = briefData.markdown;
const placeholder = '<!-- AI_SECTION_PLACEHOLDER -->';
if (enhancedMarkdown.includes(placeholder)) {
  enhancedMarkdown = enhancedMarkdown.replace(placeholder, ai);
} else {
  const dashboardEnd = enhancedMarkdown.indexOf('## 🌍 GEOGRAPHIC DISTRIBUTION');
  if (dashboardEnd > -1) {
    enhancedMarkdown = enhancedMarkdown.slice(0, dashboardEnd) + ai + enhancedMarkdown.slice(dashboardEnd);
  } else {
    enhancedMarkdown += ai;
  }
}

// ============================================================
// ENHANCE SLACK TEXT
// ============================================================
let enhancedSlack = briefData.slack_text;
const slackInsertPoint = enhancedSlack.indexOf('📊 *INDUSTRY IMPACT:*');
let aiSlack = `🤖 *AI THREAT INTELLIGENCE (Claude):*\n`;
aiSlack += `• Assessment: *${threatLevel}* — 85% confidence\n`;
if (ttps.length > 0) {
  aiSlack += `• MITRE TTPs Identified: ${ttps.length}\n`;
  ttps.slice(0, 4).forEach(t => {
    aiSlack += `  › ${t.technique || 'N/A'}\n`;
  });
}
aiSlack += `• Defensive Recommendations: ${recommendations.length}\n`;
aiSlack += `• Time-to-Encrypt: *< 48 hours*\n\n`;
aiSlack += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

if (slackInsertPoint > -1) {
  enhancedSlack = enhancedSlack.slice(0, slackInsertPoint) + aiSlack + enhancedSlack.slice(slackInsertPoint);
} else {
  enhancedSlack += `\n\n` + aiSlack;
}

// Add priority actions to end of Slack
let actionsSlack = `\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
actionsSlack += `🛡️ *PRIORITY ACTIONS:*\n`;
recommendations.slice(0, 4).forEach((rec, i) => {
  const pri = i < 2 ? '🔴 P1' : '🟠 P2';
  actionsSlack += `${pri} — ${rec.substring(0, 80)}\n`;
});
enhancedSlack += actionsSlack;

// ============================================================
// RETURN
// ============================================================
return [{
  json: {
    ...briefData,
    markdown: enhancedMarkdown,
    slack_text: enhancedSlack,
    ai_analysis: {
      threat_level: threatLevel,
      ttps: ttps,
      targeting_patterns: targeting,
      operational_intelligence: opIntel,
      recommendations: recommendations
    }
  }
}];

// ============================================================
// OUTPUT HTML FILE (v3 — matches Ransomware_Threat_Brief_Sample)
// ============================================================
const items = $input.all();
if (items.length === 0 || !items[0].json) {
  return [{ json: { error: 'No data found' } }];
}

const d = items[0].json;
const now = d.generated_at || new Date().toISOString().split('T')[0];
const reportId = d.report_id || `RTI-${now.replace(/-/g, '')}-001`;
const tl = (d.threat_level || 'UNKNOWN').replace(/^[^\s]+\s/, ''); // strip emoji
const rs = parseFloat(d.risk_score || 0);
const vc = d.victim_count || 0;
const gc = d.group_count || 0;
const cc = d.countries_affected || 0;
const ic = d.industries_affected || 0;
const vpd = d.victims_per_day || (vc / (d.days_monitored || 30));
const days = d.days_monitored || 30;
const groups = d.groups || [];
const ai = d.ai_analysis || {};
const ttps = ai.ttps || [];
const targeting = ai.targeting_patterns || {};
const opIntel = ai.operational_intelligence || '';
const recs = ai.recommendations || [];
const topInd = d.top_industries || [];
const topCo = d.top_countries || [];
const rc = d.risk_components || { freq: 5, crit: 6, geo: 4, soph: 6, time_to_encrypt: 8, double_extortion: 9 };

const esc = (s) => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');

// Badge color based on threat level
const tlColor = tl.includes('CRITICAL') ? 'var(--red)' : tl.includes('HIGH') ? 'var(--orange)' : 'var(--yellow)';
const rsColor = rs >= 8 ? 'var(--red)' : rs >= 6 ? 'var(--orange)' : 'var(--yellow)';

// Sev badge
const sevBadge = (s) => {
  const m = { CRITICAL: 'sev-critical', HIGH: 'sev-high', MEDIUM: 'sev-medium', LOW: 'sev-low' };
  return `<span class="sev ${m[s] || 'sev-medium'}">${esc(s || 'High')}</span>`;
};

// TTP rows with MITRE ID
let ttpTableRows = '';
ttps.forEach((t, i) => {
  ttpTableRows += `<tr><td class="center">${i + 1}</td><td><strong>${esc(t.mitre_id || '')}</strong></td><td>${esc(t.tactic)}</td><td>${esc(t.technique)}</td><td class="center">${sevBadge(t.severity)}</td></tr>`;
});

// TTP detail rows (expandable)
let ttpDetailRows = '';
ttps.forEach(t => {
  ttpDetailRows += `<tr><td><strong>${esc(t.mitre_id || t.tactic)}</strong></td><td>${esc(t.description)}</td></tr>`;
});

// Recommendations
let recRows = '';
recs.forEach((r) => {
  const action = r.action || r;
  const mitre = r.mitre_addresses || '';
  const effort = r.effort || 'Medium';
  const pri = r.priority === 1 || recs.indexOf(r) < 2 ? '<span class="pri pri-1">P1</span>' : '<span class="pri pri-2">P2</span>';
  const effortSev = effort === 'Low' ? 'sev-low' : effort === 'High' ? 'sev-high' : 'sev-medium';
  recRows += `<tr><td class="center">${pri}</td><td>${esc(action)}</td><td class="center" style="font-size:0.8rem">${esc(mitre)}</td><td class="center"><span class="sev ${effortSev}">${esc(effort)}</span></td></tr>`;
});

// Industry table
let indRows = '';
topInd.forEach(([ind, n]) => {
  const pct = ((n / vc) * 100).toFixed(1);
  const risk = n > 5 ? 'sev-critical' : n > 2 ? 'sev-high' : 'sev-medium';
  const label = n > 5 ? 'Critical' : n > 2 ? 'High' : 'Medium';
  indRows += `<tr><td>${esc(ind)}</td><td class="center">${n}</td><td class="center">${pct}%</td><td class="center"><span class="sev ${risk}">${label}</span></td></tr>`;
});

// Country table
let coRows = '';
topCo.forEach(([co, n], i) => {
  const pct = ((n / vc) * 100).toFixed(1);
  const dots = n > 5 ? '<span style="color:var(--red)">&#9679;&#9679;&#9679;</span>' : n > 2 ? '<span style="color:var(--orange)">&#9679;&#9679;</span>' : '<span style="color:var(--yellow)">&#9679;</span>';
  coRows += `<tr><td class="center">${i + 1}</td><td>${esc(co)}</td><td class="center">${n}</td><td class="center">${pct}%</td><td class="center">${dots}</td></tr>`;
});

// Group cards HTML
const groupColors = ['var(--red)', 'var(--accent)', 'var(--orange)', 'var(--purple)', 'var(--cyan)', 'var(--green)'];
let groupCardsHtml = '';
let groupChartInits = '';
groups.forEach((g, gi) => {
  const scoreColor = g.score >= 8.5 ? 'var(--red)' : g.score >= 7 ? 'var(--orange)' : 'var(--yellow)';
  const scoreVal = parseFloat(g.score).toFixed(1);
  const chartId = `chartGroup${gi}`;
  const indLabels = JSON.stringify(g.top_industries.map(x => x[0]));
  const indData = JSON.stringify(g.top_industries.map(x => x[1]));

  groupCardsHtml += `
    <div class="group-card">
      <div class="group-header">
        <h3>${esc(g.name)}</h3>
        <span class="score" style="color:${scoreColor};">Score: ${scoreVal} / 10</span>
      </div>
      <div class="group-body">
        <div>
          <table><tbody>
            <tr><td><strong>Victims</strong></td><td>${g.victim_count}</td></tr>
            <tr><td><strong>Countries</strong></td><td>${g.top_countries.map(x => x[0]).join(', ') || 'N/A'}</td></tr>
            <tr><td><strong>Origin</strong></td><td>${esc(g.locations)}</td></tr>
            <tr><td><strong>Industries</strong></td><td>${g.top_industries.slice(0, 2).map(x => x[0]).join(', ') || 'Mixed'}</td></tr>
          </tbody></table>
          ${g.description ? `<p style="margin-top:0.8rem;font-size:0.85rem;color:var(--text-muted);">${esc(g.description.substring(0, 200))}</p>` : ''}
