      </div>
    </div>`;

  groupChartInits += `new Chart(document.getElementById('${chartId}'), { type:'doughnut', data:{ labels:${indLabels}, datasets:[{ data:${indData}, backgroundColor:C.slice(0,${g.top_industries.length}), borderWidth:0, hoverOffset:6 }] }, options:pieCfg });\n`;
});

// Chart data
const geoLabels = JSON.stringify(topCo.map(c => c[0]));
const geoData = JSON.stringify(topCo.map(c => c[1]));
const indChartLabels = JSON.stringify(topInd.map(i => i[0]));
const indChartData = JSON.stringify(topInd.map(i => i[1]));

// TTP severity for polar chart
const sevOrder = ['CRITICAL', 'HIGH', 'MEDIUM', 'LOW'];
const sevValues = { CRITICAL: 9, HIGH: 7, MEDIUM: 5, LOW: 3 };
let ttpPolarLabels = [], ttpPolarData = [];
ttps.forEach(t => {
  ttpPolarLabels.push(`${t.mitre_id || t.tactic} ${t.technique ? t.technique.substring(0, 20) : ''}`);
  ttpPolarData.push(sevValues[t.severity] || 6);
});

// Group comparison data
const groupNames = JSON.stringify(groups.map(g => g.name));
const groupVictims = JSON.stringify(groups.map(g => g.victim_count));
const groupScores = JSON.stringify(groups.map(g => parseFloat(g.score)));

// Risk radar values
const riskRadarData = JSON.stringify([
  rc.freq || 5,
  rc.crit || 6,
  rc.geo || 4,
  rc.soph || 6,
  rc.time_to_encrypt || 8,
  rc.double_extortion || 9
]);

// Risk matrix table
const riskRows = [
  ['Attack Frequency', rc.freq || 5, 20, ((rc.freq || 5) * 0.20).toFixed(2)],
  ['Industry Criticality', rc.crit || 6, 25, ((rc.crit || 6) * 0.25).toFixed(2)],
  ['Geographic Spread', rc.geo || 4, 10, ((rc.geo || 4) * 0.10).toFixed(2)],
  ['Actor Sophistication', rc.soph || 6, 20, ((rc.soph || 6) * 0.20).toFixed(2)],
  ['Time-to-Encrypt', rc.time_to_encrypt || 8, 15, ((rc.time_to_encrypt || 8) * 0.15).toFixed(2)],
  ['Double Extortion', rc.double_extortion || 9, 10, ((rc.double_extortion || 9) * 0.10).toFixed(2)],
];
let riskTableRows = riskRows.map(([name, score, weight, weighted]) =>
  `<tr><td>${name}</td><td class="center">${score}</td><td class="center">${weight}%</td><td class="center">${weighted}</td></tr>`
).join('');

// Targeting table rows
let targetingRows = '';
if (targeting.industries?.length) targetingRows += `<tr><td><strong>Primary Industries</strong></td><td>${targeting.industries.join(', ')}</td></tr>`;
if (targeting.regions?.length) targetingRows += `<tr><td><strong>Geographic Focus</strong></td><td>${targeting.regions.join(', ')}</td></tr>`;
if (targeting.victim_profile) targetingRows += `<tr><td><strong>Victim Profile</strong></td><td>${esc(targeting.victim_profile)}</td></tr>`;
if (targeting.selection_criteria) targetingRows += `<tr><td><strong>Selection Criteria</strong></td><td>${esc(targeting.selection_criteria)}</td></tr>`;

// AI provider label
