    --cyan: #39d2c0; --pink: #f97583;
  }
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { background: var(--bg); color: var(--text); font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Helvetica, Arial, sans-serif; line-height: 1.6; }
  .container { max-width: 1280px; margin: 0 auto; padding: 2rem; }
  .header { text-align: center; padding: 3rem 2rem 2rem; border-bottom: 1px solid var(--border); margin-bottom: 2rem; }
  .header h1 { font-size: 1.8rem; letter-spacing: 2px; margin-bottom: 0.5rem; }
  .header .meta { color: var(--text-muted); font-size: 0.9rem; margin-bottom: 0.8rem; }
  .header code { background: var(--surface2); padding: 2px 8px; border-radius: 4px; font-size: 0.85rem; color: var(--orange); }
  .badge { display: inline-block; padding: 6px 20px; border-radius: 20px; font-weight: 700; font-size: 0.95rem; }
  .badge-high { background: rgba(210,153,34,0.15); color: var(--orange); border: 1px solid var(--orange); }
  .badge-critical { background: rgba(248,81,73,0.15); color: var(--red); border: 1px solid var(--red); }
  .tldr { background: var(--surface); border-left: 4px solid var(--accent); padding: 1.2rem 1.5rem; border-radius: 0 8px 8px 0; margin-bottom: 2rem; font-size: 0.95rem; }
  .tldr strong { color: var(--accent); }
  .section { margin-bottom: 2.5rem; }
  .section h2 { font-size: 1.35rem; margin-bottom: 1rem; padding-bottom: 0.5rem; border-bottom: 1px solid var(--border); }
  .section h3 { font-size: 1.05rem; color: var(--text-muted); margin: 1.5rem 0 0.75rem; }
  .kpi-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 1rem; margin-bottom: 1.5rem; }
  .kpi { background: var(--surface); border: 1px solid var(--border); border-radius: 12px; padding: 1.2rem; text-align: center; transition: border-color 0.2s; }
  .kpi:hover { border-color: var(--accent); }
  .kpi .value { font-size: 2rem; font-weight: 800; color: var(--accent); }
  .kpi .label { font-size: 0.75rem; color: var(--text-muted); text-transform: uppercase; letter-spacing: 1px; margin-top: 0.3rem; }
  .kpi .delta { font-size: 0.72rem; margin-top: 0.2rem; font-weight: 600; }
  .delta-up { color: var(--red); }
  .delta-stable { color: var(--text-muted); }
  table { width: 100%; border-collapse: collapse; margin: 1rem 0; font-size: 0.86rem; }
  th { background: var(--surface2); color: var(--text-muted); text-transform: uppercase; font-size: 0.72rem; letter-spacing: 0.5px; padding: 10px 12px; text-align: left; border-bottom: 2px solid var(--border); }
  td { padding: 10px 12px; border-bottom: 1px solid var(--border); }
  tr:hover td { background: rgba(88,166,255,0.04); }
  .center { text-align: center; }
  .sev { display: inline-block; padding: 2px 10px; border-radius: 12px; font-size: 0.72rem; font-weight: 600; }
  .sev-critical { background: rgba(248,81,73,0.15); color: var(--red); }
  .sev-high { background: rgba(210,153,34,0.15); color: var(--orange); }
  .sev-medium { background: rgba(227,179,65,0.15); color: var(--yellow); }
  .sev-low { background: rgba(63,185,80,0.15); color: var(--green); }
  .pri { display: inline-block; padding: 3px 12px; border-radius: 12px; font-size: 0.75rem; font-weight: 700; }
  .pri-1 { background: rgba(248,81,73,0.2); color: var(--red); }
  .pri-2 { background: rgba(210,153,34,0.2); color: var(--orange); }
  .chart-row { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin: 1.5rem 0; }
  .chart-box { background: var(--surface); border: 1px solid var(--border); border-radius: 12px; padding: 1.5rem; }
  .chart-box h4 { text-align: center; color: var(--text-muted); font-size: 0.8rem; margin-bottom: 1rem; text-transform: uppercase; letter-spacing: 1px; }
  .chart-box canvas { max-height: 260px; }
  .ai-section { background: linear-gradient(135deg, rgba(88,166,255,0.06), rgba(188,140,255,0.06)); border: 1px solid rgba(88,166,255,0.2); border-radius: 12px; padding: 2rem; margin-bottom: 2rem; }
  .ai-section h2 { border-bottom-color: rgba(88,166,255,0.3); }
  .ai-powered { display: inline-block; background: rgba(188,140,255,0.15); color: var(--purple); padding: 4px 12px; border-radius: 16px; font-size: 0.72rem; font-weight: 600; margin-bottom: 1rem; letter-spacing: 0.5px; }
  .ai-stat-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 1rem; margin: 1.5rem 0; }
  .ai-stat { background: rgba(88,166,255,0.05); border: 1px solid rgba(88,166,255,0.15); border-radius: 10px; padding: 1rem; text-align: center; }
  .ai-stat .val { font-size: 1.6rem; font-weight: 800; color: var(--purple); }
  .ai-stat .lbl { font-size: 0.72rem; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.5px; margin-top: 0.2rem; }
  .lifecycle { display: flex; gap: 2px; margin: 1.5rem 0; }
  .lifecycle-step { flex: 1; text-align: center; padding: 1rem 0.4rem; position: relative; }
  .lifecycle-step .icon { font-size: 1.6rem; margin-bottom: 0.3rem; }
  .lifecycle-step .step-title { font-weight: 700; font-size: 0.78rem; margin-bottom: 0.2rem; }
  .lifecycle-step .step-detail { font-size: 0.68rem; color: var(--text-muted); line-height: 1.3; }
  .lifecycle-step::after { content: '\\2192'; position: absolute; right: -6px; top: 50%; transform: translateY(-50%); font-size: 1rem; color: var(--text-muted); z-index: 1; }
  .lifecycle-step:last-child::after { display: none; }
  .lc-1 { background: rgba(231,76,60,0.12); border-radius: 10px 0 0 10px; }
  .lc-2 { background: rgba(230,126,34,0.12); }
  .lc-3 { background: rgba(243,156,18,0.12); }
  .lc-4 { background: rgba(52,152,219,0.12); }
  .lc-5 { background: rgba(155,89,182,0.12); }
  .lc-6 { background: rgba(192,57,43,0.12); border-radius: 0 10px 10px 0; }
  .group-card { background: var(--surface); border: 1px solid var(--border); border-radius: 12px; padding: 1.5rem; margin-bottom: 1.5rem; }
  .group-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 1rem; }
  .group-header h3 { margin: 0; font-size: 1.1rem; }
  .score { font-size: 0.88rem; font-weight: 700; }
  .group-body { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; }
  .group-body canvas { max-height: 200px; }
  .insight-box { background: var(--surface); border: 1px solid var(--border); border-left: 4px solid var(--cyan); border-radius: 0 8px 8px 0; padding: 1rem 1.2rem; margin: 1rem 0; font-size: 0.88rem; }
  .insight-box strong { color: var(--cyan); }
  blockquote { border-left: 3px solid var(--accent); padding: 0.8rem 1.2rem; margin: 1rem 0; background: var(--surface); border-radius: 0 8px 8px 0; color: var(--text-muted); font-size: 0.88rem; }
  blockquote strong { color: var(--text); }
  details { background: var(--surface); border: 1px solid var(--border); border-radius: 8px; margin: 1rem 0; }
  summary { padding: 1rem 1.5rem; cursor: pointer; font-weight: 600; color: var(--text-muted); }
  summary:hover { color: var(--accent); }
  details[open] summary { border-bottom: 1px solid var(--border); }
  details > div { padding: 1rem 1.5rem; }
  .risk-total { font-size: 1.4rem; font-weight: 800; text-align: center; margin: 1rem 0; }
  .disclaimer { background: var(--surface); border: 1px solid var(--border); border-radius: 8px; padding: 1.2rem 1.5rem; margin-top: 2rem; font-size: 0.8rem; color: var(--text-muted); }
  .footer { text-align: center; color: var(--text-muted); font-size: 0.78rem; margin-top: 2rem; padding-top: 1.5rem; border-top: 1px solid var(--border); }
  @media (max-width: 768px) { .chart-row, .group-body { grid-template-columns: 1fr; } .lifecycle { flex-wrap: wrap; } .lifecycle-step { min-width: 100%; border-radius: 8px !important; margin-bottom: 0.3rem; } .lifecycle-step::after { display: none; } .kpi-grid { grid-template-columns: repeat(2, 1fr); } }
</style>
</head>
